const items = $input.all();

// --------------------------------------------------
// 1) LOCALIZAR A LINHA DE CABEÇALHO (row_number = 10)
// --------------------------------------------------
const headerItem = items.find(item => Number(item.json.row_number) === 10);

if (!headerItem) {
  throw new Error('Não foi encontrada a linha 10 para usar como cabeçalho.');
}

// --------------------------------------------------
// 2) MONTAR MAPA DE CABEÇALHOS
//    - usa os valores da linha 10 como nome das chaves
//    - trata cabeçalhos repetidos
// --------------------------------------------------
const headerMap = {};
const usedHeaders = {};

for (const key of Object.keys(headerItem.json)) {
  if (key === 'row_number') continue;

  let headerName = String(headerItem.json[key] ?? '').trim();

  if (!headerName) {
    headerName = key;
  }

  if (usedHeaders[headerName]) {
    usedHeaders[headerName] += 1;
    headerName = `${headerName}_${usedHeaders[headerName]}`;
  } else {
    usedHeaders[headerName] = 1;
  }

  headerMap[key] = headerName;
}

// --------------------------------------------------
// 3) FUNÇÕES DE DATA
//    - extrai data do texto
//    - mantém formato DD/MM/AAAA
// --------------------------------------------------
function formatDateToBR(dateStr) {
  if (!dateStr) return '';

  const s = String(dateStr).trim();

  // DD/MM/AAAA ou DD-MM-AAAA
  let m = s.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})$/);
  if (m) {
    let [, dd, mm, yyyy] = m;

    dd = dd.padStart(2, '0');
    mm = mm.padStart(2, '0');

    return `${dd}/${mm}/${yyyy}`;
  }

  // AAAA-MM-DD ou AAAA/MM/DD
  m = s.match(/^(\d{4})[\/\-](\d{1,2})[\/\-](\d{1,2})$/);
  if (m) {
    let [, yyyy, mm, dd] = m;

    dd = dd.padStart(2, '0');
    mm = mm.padStart(2, '0');

    return `${dd}/${mm}/${yyyy}`;
  }

  return '';
}

function extractData(texto) {
  const raw = String(texto ?? '').trim();
  if (!raw) return '';

  // tenta pegar a data depois da última letra "a"
  const partes = raw.split(/a/i).map(s => s.trim()).filter(Boolean);
  if (partes.length > 1) {
    const ultimaParte = partes[partes.length - 1];

    const dateMatch =
      ultimaParte.match(/\d{1,2}[\/\-]\d{1,2}[\/\-]\d{4}/) ||
      ultimaParte.match(/\d{4}[\/\-]\d{1,2}[\/\-]\d{1,2}/);

    if (dateMatch) {
      return formatDateToBR(dateMatch[0]);
    }
  }

  // fallback: procura qualquer data no texto inteiro
  const anyDateMatch =
    raw.match(/\d{1,2}[\/\-]\d{1,2}[\/\-]\d{4}/) ||
    raw.match(/\d{4}[\/\-]\d{1,2}[\/\-]\d{1,2}/);

  if (anyDateMatch) {
    return formatDateToBR(anyDateMatch[0]);
  }

  return '';
}

