// 4) BUSCAR UM TEXTO GLOBAL QUE TENHA DATA
// --------------------------------------------------
function findTextoBaseComData() {
  for (const item of items) {
    const valor = item.json["Estatísticas por Convênio"];
    const data = extractData(valor);
    if (data) {
      return String(valor);
    }
  }
  return '';
}

