  .filter(item => Number(item.json.row_number) >= 11)
  .map(item => {
    const original = item.json;
    const novoObjeto = {};

    for (const originalKey of Object.keys(headerMap)) {
      const novoNome = headerMap[originalKey];
      novoObjeto[novoNome] = original[originalKey];
    }

    const textoAtual = original["Estatísticas por Convênio"] ?? '';
    let data = extractData(textoAtual);

    if (!data) {
      data = extractData(textoBaseGlobal);
    }

    let sigla = String(novoObjeto["Sigla"] ?? '').trim();

    // remove zero à esquerda se a sigla vier numérica, ex: 090 -> 90
    if (/^\d+$/.test(sigla)) {
      sigla = String(Number(sigla));
    }

    const chaveMatch = `${data} | ${sigla} | (+)COMPUTADOR DO POSTO`;

    return {
      json: {
        ...novoObjeto,
        data,
        chaveMatch
      }
    };
  });

return resultado;

