  .replace(/```$/i, "")
  .trim();

// ======================================================
// LOCALIZA OBJETO JSON
// Esperado:
// {
//   "tipoRelatorio": "...",
//   "registros": [...]
// }
// ======================================================
const inicio = texto.indexOf("{");
const fim = texto.lastIndexOf("}");

if (inicio === -1 || fim === -1 || fim <= inicio) {
  throw new Error("A resposta da IA não contém um objeto JSON válido.");
}

const jsonLimpo = texto.slice(inicio, fim + 1);

let dados;

try {
  dados = JSON.parse(jsonLimpo);
} catch (error) {
  throw new Error("Erro ao converter resposta da IA em JSON: " + error.message);
}

// ======================================================
// VALIDA ESTRUTURA
// ======================================================
if (!dados || typeof dados !== "object" || Array.isArray(dados)) {
  throw new Error("O JSON retornado pela IA não é um objeto válido.");
}

if (!Array.isArray(dados.registros)) {
  throw new Error("O JSON retornado pela IA não contém o array 'registros'.");
}

// ======================================================
// DADOS GERAIS DO RELATÓRIO
// ======================================================
const tipoRelatorio = dados.tipoRelatorio || null;
const arquivo = dados.arquivo || null;

const periodo = dados.periodo || {
  inicio: null,
  fim: null
};

const totais = dados.totais || {
  numeroPacientesListados: null,
  numeroExamesEfetuados: null,
  valorFaturadoTotal: null
};

const impressao = dados.impressao || {
  dataImpressao: null,
  usuario: null
};

// ======================================================
// RETORNA UM ITEM POR POSTO / REGISTRO
// ======================================================
return dados.registros.map((registro, index) => ({
  json: {
    sucesso: true,

    tipoRelatorio,
    arquivo,

    periodoInicio: periodo.inicio || null,
    periodoFim: periodo.fim || null,

    posto: registro.posto ?? null,
    local: registro.local ?? null,
    req: registro.req ?? null,
    exames: registro.exames ?? null,
    valor: registro.valor ?? null,
    area: registro.area ?? null,
    responsavel: registro.responsavel ?? null,

    numeroPacientesListados: totais.numeroPacientesListados ?? null,
    numeroExamesEfetuados: totais.numeroExamesEfetuados ?? null,
    valorFaturadoTotal: totais.valorFaturadoTotal ?? null,

    dataImpressao: impressao.dataImpressao || null,
    usuario: impressao.usuario || null,

    _idx: index + 1,
    _totalRegistros: dados.registros.length
  }
}));
